// Dummy 13 — faithful parametric reconstruction of all 21 frame parts
// (soozafone, CC-BY-4.0), inverse-cad v2: every part passes exact-distance +
// topology + volume gates vs the original STL (mean chamfer 0.006mm; hands
// smooth via levelSet section interpolation). Laid out as a print plate.
const { Manifold, CrossSection, geom } = api;

function make_adapter_stand() {
  // adapter_stand — keyhole hanger. Every dimension probed from target.stl:
  //   ball: sphere r=3.000 @ (0,-5.5,2.5)  (probe fit: rms 0, inlierFrac 1.0)
  //   neck: revolved traced r(y) polyline (band circle fits rms<0.001 + back-face rays;
  //         single arc/cone fits were REJECTED: worst resid 0.05, curve is not one arc)
  //   flange: disc r=4.0, rim y in [-1,0], front face y=0, curved back blending into neck
  //   loop: outer circle R=1.4997 @ (0,2.1) + straight foot ±1.2 down to flange face;
  //         inner circle r=0.6592 @ (0,2.1) + slot ±0.36; prismatic, extruded z 0..3
  //   whole part clipped flat at z=0 (print bed)

  const AXIS_Z = 2.5; // revolve axis height (all band circle fits: cy=2.500)
  const BALL_Y = -5.5, BALL_R = 3.0;

  // measured neck polyline (y, r) — band circle fits (mid-band) then back-face rays
  const neck = [
    [-3.048, 1.7433], [-2.948, 1.6694], [-2.848, 1.6267], [-2.698, 1.6078],
    [-2.548, 1.6298], [-2.448, 1.6733], [-2.348, 1.7252], [-2.248, 1.7827],
    [-2.148, 1.8464], [-2.048, 1.9169], [-1.948, 1.9949], [-1.848, 2.0814],
    [-1.748, 2.1777], [-1.648, 2.2852], [-1.548, 2.4060], [-1.448, 2.5417],
    [-1.4109, 2.6], [-1.2947, 2.8], [-1.2005, 3.0], [-1.1271, 3.2],
    [-1.0709, 3.4], [-1.0313, 3.6], [-1.0181, 3.7], [-1.0025, 3.9], [-1.0, 4.0],
  ];

  // profile polygon in the revolve half-plane: X = radius, Y = height (-> global Y)
  const prof = [[0, BALL_Y - BALL_R]];
  const yStartNeck = neck[0][0];
  const t1 = Math.acos(-(yStartNeck - BALL_Y) / BALL_R);
  const N = 48;
  for (let i = 1; i <= N; i++) {
    const t = (t1 * i) / N;
    prof.push([BALL_R * Math.sin(t), BALL_Y - BALL_R * Math.cos(t)]);
  }
  for (const [y, r] of neck) prof.push([r, y]);
  prof.push([4.0, -1.0]);
  prof.push([4.0, 0.0]);
  prof.push([0, 0]);
  // force CCW winding
  let area2 = 0;
  for (let i = 0; i < prof.length; i++) {
    const [x1, y1] = prof[i], [x2, y2] = prof[(i + 1) % prof.length];
    area2 += x1 * y2 - x2 * y1;
  }
  if (area2 < 0) prof.reverse();

  const body = geom.fromPoints(prof).revolve(128) // axis = Z, heights = profile Y
    .rotate([-90, 0, 0])                          // height axis Z -> +Y
    .translate([0, 0, AXIS_Z]);

  // keyhole loop, extruded along Z from 0 to 3 (prismatic: verified z=0.3/2.7/2.95)
  const R_OUT = 1.4997, R_IN = 0.6592, LOOP_CY = 2.1;
  const outer = CrossSection.circle(R_OUT, 96).translate([0, LOOP_CY])
    .add(CrossSection.square([2.4, 1.7], false).translate([-1.2, -0.5])); // foot ±1.2, y -0.5..1.2
  const inner = CrossSection.circle(R_IN, 64).translate([0, LOOP_CY])
    .add(CrossSection.square([0.72, 1.6], false).translate([-0.36, 0]));  // slot ±0.36, y 0..1.6
  const loop = outer.subtract(inner).extrude(3.0);

  const part = body.add(loop);
  // print-bed clip at z=0
  const ground = Manifold.cube([40, 40, 10], true).translate([0, -2.45, -5]);
  return part.subtract(ground);
}

function make_frame_abdomen() {
  // frame_abdomen — probe-driven primitive composition
  // All numbers measured (probe fit / ray / section):
  //  - disc: z-cylinder r=4.500 about origin, z ±2.5, 45° leg-0.5 chamfers |z|>2
  //  - mouth wedge: planes y = -0.6682|x| through socket center, chamfered leg 0.5 near z faces
  //  - corner chamfer lines: y = 0.2279x - 2.9803 (mirror), unchamfered (hip_shoulder spec mirrored)
  //  - socket sphere r=2.8488 @ origin; entry cones r(z)=2.3677-0.3525*(2.5-|z|) both faces
  //  - bulge: ellipse prism (3.2, 2.5) y 2.5..4.8, 45° chamfer to (3.0,2.3) at y=5.0
  //  - body: Y-cylinder r=3.000 to y=8.5, 45° leg-0.5 chamfer to r=2.5 at end face y=9.0
  //  - neck: D-section r=1.500 flat at z=-1.3, y 8.5..11.2
  //  - ball: sphere r=3.000 @ (0,13,0), clipped z ±2.5

  const SEG = 128;

  // ---- disc (r4.5 about origin, chamfered arc edges)
  const discCore = Manifold.cylinder(4.02, 4.5, 4.5, SEG, true); // z -2.01..2.01
  const discTop = Manifold.cylinder(0.5, 4.5, 4.0, SEG).translate([0, 0, 2.0]);
  const disc = discCore.add(discTop).add(discTop.mirror([0, 0, 1]));

  // helper: extrude a cross-section along +Y from y0 to y1 (optional scaleTop)
  function alongY(cs, y0, y1, scaleTop) {
    return cs.extrude(y1 - y0, 0, 0, scaleTop || [1, 1])
      .rotate([-90, 0, 0])
      .translate([0, y0, 0]);
  }

  // ---- bulge: ellipse (3.2, 2.5)
  const ell = CrossSection.circle(1, SEG).scale([3.2, 2.5]);
  const bulge = alongY(ell, 2.5, 4.81)
    .add(alongY(ell, 4.8, 5.0, [3.0 / 3.2, 2.3 / 2.5]));

  // ---- body: Y-cylinder r=3 with end chamfer
  const c3 = CrossSection.circle(3.0, SEG);
  const body = alongY(c3, 3.0, 8.51)
    .add(alongY(c3, 8.5, 9.0, [2.5 / 3.0, 2.5 / 3.0]));

  // ---- neck: D-section r=1.5, flat at world z=-1.3 (cs Y <= 1.3 since world z = -csY)
  const neckCS = CrossSection.circle(1.5, 96)
    .intersect(CrossSection.square([4, 2.8]).translate([-2, -1.5]));
  const neck = alongY(neckCS, 8.5, 11.2);

  // ---- ball r=3 @ (0,13,0), clipped z ±2.5
  const ball = Manifold.sphere(3.0, SEG)
    .intersect(Manifold.cube([8, 8, 5], true))
    .translate([0, 13, 0]);

  // global z-clip: everything lives in |z| <= 2.5 (body r3 and ball r3 poke past)
  let solid = disc.add(bulge).add(body).add(neck).add(ball)
    .intersect(Manifold.cube([22, 26, 5], true).translate([0, 6.9, 0]));

  // ---- mouth wedge cut with leg-0.5 45° chamfers near z faces (§5.11 wedge prism)
  // profile in (s, z): cut where s <= f(z); f=0 for |z|<=2, |z|-2 for 2..2.5, 0.5 beyond
  const mouthProf = geom.fromPoints([
    [-8, -3], [0.5, -3], [0.5, -2.5], [0, -2], [0, 2], [0.5, 2.5], [0.5, 3], [-8, 3],
  ]);
  function mouthCut(nx, ny) {
    const th = Math.atan2(ny, nx) * 180 / Math.PI;
    return mouthProf.extrude(14, 0, 0, [1, 1])
      .translate([0, 0, -7])
      .rotate([90, 0, 0])
      .rotate([0, 0, th]);
  }
  // planes through origin: y + 0.6682x = 0 (x>0 side), y - 0.6682x = 0 (x<0 side)
  // wedge region = INTERSECTION of the two half-spaces (y <= -0.6682|x|)
  const nlen = Math.hypot(0.6682, 1);
  const wedge = mouthCut(0.6682 / nlen, 1 / nlen)
    .intersect(mouthCut(-0.6682 / nlen, 1 / nlen));
  solid = solid.subtract(wedge);

  // ---- corner chamfer line cuts: remove y <= 0.2279x - 2.9803 (and mirror)
  const cornerPoly = geom.fromPoints([
    [2, -5], [6, -5], [6, 0.2279 * 6 - 2.9803], [2, 0.2279 * 2 - 2.9803],
  ]);
  const cornerCut = cornerPoly.extrude(6, 0, 0, [1, 1]).translate([0, 0, -3]);
  solid = solid.subtract(cornerCut).subtract(cornerCut.mirror([1, 0, 0]));

  // ---- socket sphere + entry cones (subtract from assembled body)
  solid = solid.subtract(Manifold.sphere(2.8488, SEG));
  // cone: r = 2.3677 - 0.3525*(2.5-z); extended z 1.7..3.0
  const coneCut = Manifold.cylinder(1.3, 2.3677 - 0.3525 * 0.8, 2.3677 + 0.3525 * 0.5, SEG)
    .translate([0, 0, 1.7]);
  solid = solid.subtract(coneCut).subtract(coneCut.mirror([0, 0, 1]));

  return solid;
}

function make_frame_ankle_2x() {
  // frame_ankle_2x — CAD reconstruction
  // ring disk r4.5 + neck + lobe, keyhole prism, sphere socket + conical entry
  // chamfers, 45deg 0.5x0.5 ring edge chamfers (stepped offsets).
  // All numbers measured via probe.mjs (sections + sphere fit).

  const SEG = 128;
  const cx = 0.0008, cy = -0.0015;      // socket center (probe fit)
  const sphR = 2.9046;                  // probe fit, 99.1% inliers
  const ringR = 4.5;                    // traced outer arc radius
  const zTop = 5;
  const CH = 0.5;                       // ring edge chamfer (measured 45deg, w=h=0.5)

  // ---- ring 2D profile ----
  let ring = CrossSection.circle(ringR, SEG);
  // bottom cut y >= -4
  ring = ring.subtract(geom.fromPoints([[-8, -4], [8, -4], [8, -10], [-8, -10]]));
  // left tip cut y <= 2.96
  ring = ring.subtract(geom.fromPoints([[-8, 2.96], [8, 2.96], [8, 10], [-8, 10]]));
  // right tip chord through [4.3733,1.0605]-[3.7588,1.3681]
  ring = ring.subtract(geom.fromPoints([[6.22, 0.14], [1.92, 2.29], [6.40, 11.23], [10.69, 9.08]]));
  // mouth wedge: apex at socket center, 20.03deg .. 132.5deg, R=12
  const wedgePts = [[cx, cy]];
  for (const a of [20.03, 48, 76, 104, 132.5]) {
    const t = a * Math.PI / 180;
    wedgePts.push([cx + 12 * Math.cos(t), cy + 12 * Math.sin(t)]);
  }
  ring = ring.subtract(geom.fromPoints(wedgePts));

  // ---- chamfered ring solid: exact 45deg chamfers ----
  // circle edge: intersect with cone-cyl-cone envelope
  let ringSolid = ring.extrude(zTop, 0, 0, [1, 1]);
  const circEnv = Manifold.cylinder(CH, ringR - CH, ringR, SEG)
    .add(Manifold.cylinder(zTop - 2 * CH, ringR, ringR, SEG).translate([0, 0, CH]))
    .add(Manifold.cylinder(CH, ringR, ringR - CH, SEG).translate([0, 0, zTop - CH]));
  ringSolid = ringSolid.intersect(circEnv);

  // straight edges: subtract 45deg wedge prisms (bottom + top per edge).
  // Prism runs from E1 along d=(ny,-nx) for length L; halfspace n.p > c-CH+z
  // (bottom) / n.p > c-CH+(zTop-z) (top), n = outward normal, material n.p <= c.
  function edgeWedges(nx, ny, c, e1x, e1y, L) {
    const bot2d = geom.fromPoints([[c - 2.5, -2], [c, CH], [c + 12, CH], [c + 12, -2]]);
    const top2d = geom.fromPoints([[c + 12, zTop + 2], [c - 2.5, zTop + 2], [c, zTop - CH], [c + 12, zTop - CH]]);
    const theta = Math.atan2(ny, nx) * 180 / Math.PI;
    const mk = (cs) => cs.extrude(L, 0, 0, [1, 1])
      .rotate([90, 0, 0])       // (x,y,ze) -> (x,-ze,y): prism along -y, x=s, z=height
      .rotate([0, 0, theta])    // +x -> n, -y -> d=(ny,-nx)
      .translate([e1x, e1y, 0]);
    return mk(bot2d).add(mk(top2d));
  }
  // y=-4 edge (exposed only for 1.2<=|x|<=2.06; runout at |x|=1.2)
  ringSolid = ringSolid.subtract(edgeWedges(0, -1, 4, 2.6, -4, 1.4));
  ringSolid = ringSolid.subtract(edgeWedges(0, -1, 4, -1.2, -4, 1.4));
  // y=2.96 left tip cut
  ringSolid = ringSolid.subtract(edgeWedges(0, 1, 2.96, -3.9, 2.96, 1.6));
  // right tip chord (n from line [4.3733,1.0605]-[3.7588,1.3681])
  ringSolid = ringSolid.subtract(edgeWedges(0.4476, 0.8942, 2.9056, 3.133, 1.681, 2.1));
  // mouth wedge faces L1 (132.5deg) and L2 (20.03deg), apex at socket center
  const u1x = Math.cos(132.5 * Math.PI / 180), u1y = Math.sin(132.5 * Math.PI / 180);
  ringSolid = ringSolid.subtract(edgeWedges(0.7373, 0.6756, 0, cx + 4.6 * u1x, cy + 4.6 * u1y, 4.2));
  const u2x = Math.cos(20.03 * Math.PI / 180), u2y = Math.sin(20.03 * Math.PI / 180);
  ringSolid = ringSolid.subtract(edgeWedges(-0.3425, 0.9396, 0, cx + 0.4 * u2x, cy + 0.4 * u2y, 4.4));

  // ---- neck + lobe (unchamfered, full height) ----
  const lobe = CrossSection.circle(1.5, 96).translate([0, -5.5]);
  const neck = geom.fromPoints([[-1.2, -4.65], [1.2, -4.65], [1.2, -3.9], [-1.2, -3.9]]);
  const restSolid = lobe.add(neck).extrude(zTop, 0, 0, [1, 1]);

  // ---- keyhole through-hole (traced at z=2.0; prismatic, verified at z=0.05) ----
  const hole = geom.fromPoints([[0.3708, -4.7346], [0.36, -4.0], [-0.36, -4.0], [-0.3843, -4.8007], [-0.6573, -5.4407], [-0.5261, -5.8985], [-0.1211, -6.1488], [0.1211, -6.1488], [0.3972, -6.0271], [0.5606, -5.8483], [0.657, -5.5623], [0.6353, -5.3211], [0.4973, -5.0595]]);
  const holePrism = hole.extrude(6, 0, 0, [1, 1]).translate([0, 0, -0.5]);

  // ---- socket: sphere + conical entry chamfers (measured r(z)=2.4649-0.3708z) ----
  const socket = Manifold.sphere(sphR, 128).translate([cx, cy, 2.5]);
  const coneSlope = 0.3708, coneR0 = 2.4649;
  const coneBot = Manifold.cylinder(1.2, coneR0 + 0.2 * coneSlope, coneR0 - 1.0 * coneSlope, 96)
    .translate([cx, cy, -0.2]);
  const coneTop = Manifold.cylinder(1.2, coneR0 - 1.0 * coneSlope, coneR0 + 0.2 * coneSlope, 96)
    .translate([cx, cy, zTop - 1.0]);

  return ringSolid.add(restSolid)
    .subtract(holePrism)
    .subtract(socket)
    .subtract(coneBot)
    .subtract(coneTop);
}

function make_frame_chest() {
  // frame_chest — structured rebuild from probe measurements (hip_shoulder module x2 + hips archetype).
  // Plate z in [-2.5, 2.5]: lower body (spine socket block w/ arc r4.5 about (0,0), walls x=±4.5,
  // column + notches + bar x=±8 y 7..10 w/ plan corner chamfers 0.5, slot 3x3.2 @ (0,6.5)) and
  // neck ring (disc r4.5 about (0,20)). Balls r=3.000 exact @ (±6,14,0) (probe rms 0), top z=3.
  // Struts: cyl r1.5 along Y @ (x=±6, z=0), chordal flat z=-1.3 (hips archetype, ray-verified).
  // Arms: slabs z in [-1.5,1.5] between lines x+y=20 and x+y=22.5 (ray-verified z, trace-verified lines).
  // Cavities: spine sphere r2.8501 @ (0,0,0) + neck sphere r2.900 @ (0,20,0), rim entry cones both
  // faces each, mouth wedges slope 0.6682 through centers (spine opens -y, neck +y).
  // Outer 45° leg-0.5 chamfers on both faces: walls, arcs (annulus cutters), mouth lines, corner
  // lines, bar edges + plan corners, y=10, slot rim (hull frustums). NOT: notch, arms, struts.

  const p = { spineR: 2.8501, r0s: 2.372, r0n: 2.4709, slope: 0.3678, cham: 0.5 };

  const S = 0.6682;                 // mouth line slope about socket center
  const A = 0.2279, B = 2.9803;     // corner chamfer line (hip_shoulder spec, y-mirrored)
  const R = 4.5;                    // block/ring outer arc radius
  const CH = p.cham;
  const NY = 20;                    // neck socket center y

  // corner-line endpoints (spine frame, x>0, mouth toward -y): on mouth line & on arc r=R
  const xm = B / (S + A);                                         // = 3.3259
  const ym = -S * xm;                                             // = -2.2223
  const xa = (A * B + Math.sqrt(A * A * B * B - (1 + A * A) * (B * B - R * R))) / (1 + A * A);
  const ya = A * xa - B;                                          // (3.9959, -2.0695)

  // ---------- helpers ----------
  function cylY(r, y0, y1, x, z, segs) {
    return Manifold.cylinder(y1 - y0, r, r, segs).rotate([-90, 0, 0]).translate([x, y0, z]);
  }
  // 45° chamfer wedge cutter for a straight edge on the bottom face z=-2.5; n = outward unit normal.
  function chamferWedge(e1, e2, n, leg) {
    const prof = geom.fromPoints([[-leg, 0], [-leg, -0.4], [0.6, -0.4], [0.6, leg], [0, leg]]);
    const d = [n[1], -n[0]];
    const v = [e2[0] - e1[0], e2[1] - e1[1]];
    const L = Math.hypot(v[0], v[1]);
    const anchor = (v[0] * d[0] + v[1] * d[1] > 0) ? e1 : e2;
    const phi = Math.atan2(n[1], n[0]) * 180 / Math.PI;
    return prof.extrude(L).rotate([90, 0, 0]).rotate([0, 0, phi]).translate([anchor[0], anchor[1], -2.5]);
  }
  function fan(cx, cy, a0deg, a1deg, rad, steps) {
    const pts = [[cx, cy]];
    for (let i = 0; i <= steps; i++) {
      const a = ((a0deg + ((a1deg - a0deg) * i) / steps) * Math.PI) / 180;
      pts.push([cx + rad * Math.cos(a), cy + rad * Math.sin(a)]);
    }
    return geom.fromPoints(pts);
  }
  // annulus chamfer cutter about (cx,cy) for the bottom face: cuts outside the 45° cone r=R-CH+(z+2.5)
  function arcAnnulus(cx, cy) {
    const ring = Manifold.cylinder(0.75, R + 1, R + 1, 96).translate([cx, cy, -2.75]);
    const cone45 = Manifold.cylinder(0.75, R - CH - 0.25, R + 0.25, 128).translate([cx, cy, -2.75]);
    return ring.subtract(cone45);
  }

  // ---------- 2D plan ----------
  const spineDisc = CrossSection.circle(R, 128);
  const wallsRect = geom.fromPoints([[-4.5, 0], [4.5, 0], [4.5, 7], [-4.5, 7]]);
  const barOct = geom.fromPoints([[-7.5, 7], [7.5, 7], [8, 7.5], [8, 9.5], [7.5, 10], [-7.5, 10], [-8, 9.5], [-8, 7.5]]);
  // spine mouth wedge (cut region y <= -S|x|), apex at center
  const spineWedge2D = geom.fromPoints([[0, 0], [-8, -8 * S], [-8, -12], [8, -12], [8, -8 * S]]);
  // spine corner-line halfplane cuts (below y = A x - B for x>0; mirrored) — CCW
  const spineCornerCutR = geom.fromPoints([[2.8, -7], [6, -7], [6, A * 6 - B], [2.8, A * 2.8 - B]]);
  // notch cut at y in [3,3.5], from wall to x=3.25 with r0.25 rounded end
  const notchR = geom.fromPoints([[3.25, 3], [5, 3], [5, 3.5], [3.25, 3.5]]).add(CrossSection.circle(0.25, 32).translate([3.25, 3.25]));

  let lower2D = spineDisc.add(wallsRect).add(barOct)
    .subtract(spineWedge2D)
    .subtract(spineCornerCutR).subtract(spineCornerCutR.mirror([1, 0]))
    .subtract(notchR).subtract(notchR.mirror([1, 0]));

  const neckWedge2D = geom.fromPoints([[0, NY], [8, NY + 8 * S], [8, NY + 13], [-8, NY + 13], [-8, NY + 8 * S]]);
  const neckCornerCutR = geom.fromPoints([[2.8, NY + B - A * 2.8], [6, NY + B - A * 6], [6, NY + 7], [2.8, NY + 7]]);
  const ring2D = CrossSection.circle(R, 128).translate([0, NY])
    .subtract(neckWedge2D)
    .subtract(neckCornerCutR).subtract(neckCornerCutR.mirror([1, 0]));

  const plate = lower2D.add(ring2D).extrude(5, 0, 0, [1, 1]).translate([0, 0, -2.5]);

  // ---------- mid-height members ----------
  const armR = geom.fromPoints([[1.8, 18.2], [6.2, 13.8], [8.7, 13.8], [3.9, 18.6]])
    .extrude(3, 0, 0, [1, 1]).translate([0, 0, -1.5]);
  const arms = armR.add(armR.mirror([1, 0, 0]));

  const flatBox = Manifold.cube([8, 8, 8]).translate([-4, -4, -1.3]); // keep z >= -1.3
  const strutR = cylY(1.5, 9, 12.7, 6, 0, 96).intersect(flatBox.translate([6, 10.8, 0 + 0]));
  const strutL = strutR.mirror([1, 0, 0]);

  const ballR = Manifold.sphere(3, 128).translate([6, 14, 0]);
  const ballL = ballR.mirror([1, 0, 0]);

  // ---------- cavities ----------
  const spineSphere = Manifold.sphere(p.spineR, 128);
  const neckSphere = Manifold.sphere(2.900, 128).translate([0, NY, 0]);
  function coneBot(cx, cy, r0) {
    return Manifold.cylinder(0.78, r0 + 0.1 * p.slope, r0 - 0.68 * p.slope, 96).translate([cx, cy, -2.6]);
  }
  function coneTop(cx, cy, r0) {
    return Manifold.cylinder(0.78, r0 - 0.68 * p.slope, r0 + 0.1 * p.slope, 96).translate([cx, cy, 1.82]);
  }

  // slot 3 x 3.2 @ (0, 6.5) with chamfered rims (hull frustums, faces pinned on planes)
  const slotRect = geom.fromPoints([[-1.5, 4.9], [1.5, 4.9], [1.5, 8.1], [-1.5, 8.1]]);
  const slotRect2 = geom.fromPoints([[-2.0, 4.4], [2.0, 4.4], [2.0, 8.6], [-2.0, 8.6]]);
  const slotPrism = slotRect.extrude(5.2, 0, 0, [1, 1]).translate([0, 0, -2.6]);
  const slotTopCh = slotRect.extrude(0.1, 0, 0, [1, 1]).translate([0, 0, 1.9])
    .add(slotRect2.extrude(0.1, 0, 0, [1, 1]).translate([0, 0, 2.5])).hull();
  const slotBotCh = slotTopCh.mirror([0, 0, 1]);

  // ---------- outer chamfer cutters (bottom set, then z-mirrored) ----------
  const nm = 1 / Math.hypot(S, 1);
  const dM = [1 * (1 / Math.hypot(1, S)), -S * (1 / Math.hypot(1, S))]; // spine mouth dir (x>0, y<0)
  const cutters = [];
  // walls x=±4.5 (span through notch region — notch is air there)
  cutters.push(chamferWedge([4.5, -0.05], [4.5, 7.5], [1, 0], CH));
  // bar underside y=7 (x 4.0..8.1, past concave corner + convex corner)
  cutters.push(chamferWedge([4.0, 7], [8.1, 7], [0, -1], CH));
  // bar side x=8
  cutters.push(chamferWedge([8, 7.4], [8, 9.6], [1, 0], CH));
  // bar plan-corner lines
  const iv = Math.SQRT1_2;
  cutters.push(chamferWedge([7.4, 6.9], [8.1, 7.6], [iv, -iv], CH));
  cutters.push(chamferWedge([7.4, 10.1], [8.1, 9.4], [iv, iv], CH));
  // spine mouth line (x>0): from s=2.0 to s=4.2 along dM; outward normal (-S,-1)/|.|
  cutters.push(chamferWedge([2.0 * dM[0], 2.0 * dM[1]], [4.2 * dM[0], 4.2 * dM[1]], [-S * nm, -1 * nm], CH));
  // spine corner line (x>0), extended ±0.1
  cutters.push(chamferWedge([xm - 0.098, A * (xm - 0.098) - B], [xa + 0.098, A * (xa + 0.098) - B], [A / Math.hypot(1, A), -1 / Math.hypot(1, A)], CH));
  // neck mouth line (x>0): dir (dM[0], +S*..) about (0,20)
  cutters.push(chamferWedge([2.0 * dM[0], NY - 2.0 * dM[1]], [4.2 * dM[0], NY - 4.2 * dM[1]], [-S * nm, 1 * nm], CH));
  // neck corner line (x>0)
  cutters.push(chamferWedge([xm - 0.098, NY + B - A * (xm - 0.098)], [xa + 0.098, NY + B - A * (xa + 0.098)], [A / Math.hypot(1, A), 1 / Math.hypot(1, A)], CH));
  // y=10 edge (single, symmetric)
  const cutY10 = chamferWedge([-7.6, 10], [7.6, 10], [0, 1], CH);
  // spine arc annulus: sectors from -26° to -154° (through -90°)
  const spineArcCut = arcAnnulus(0, 0).intersect(fan(0, 0, -154, -26, 6.5, 12).extrude(1.2, 0, 0, [1, 1]).translate([0, 0, -2.9]));
  // neck arc annulus: full annulus minus top wedge sector (26°..154°)
  const neckArcCut = arcAnnulus(0, NY).subtract(fan(0, NY, 25, 155, 6.5, 12).extrude(1.4, 0, 0, [1, 1]).translate([0, 0, -3.0]));

  let cutBottom = cutY10.add(spineArcCut).add(neckArcCut);
  for (const c of cutters) cutBottom = cutBottom.add(c).add(c.mirror([1, 0, 0]));
  const allCut = cutBottom.add(cutBottom.mirror([0, 0, 1]));

  // ---------- assemble ----------
  const body = plate.add(arms).add(strutR).add(strutL).add(ballR).add(ballL)
    .subtract(spineSphere)
    .subtract(neckSphere)
    .subtract(coneBot(0, 0, p.r0s)).subtract(coneTop(0, 0, p.r0s))
    .subtract(coneBot(0, NY, p.r0n)).subtract(coneTop(0, NY, p.r0n))
    .subtract(slotPrism).subtract(slotTopCh).subtract(slotBotCh)
    .subtract(allCut);

  const clip = Manifold.cube([22, 30, 6.5]).translate([-11, -4, -2.5]);
  return body.intersect(clip);
}

function make_frame_clavicle_2x() {
  // frame_clavicle_2x — probe-driven primitive composition (Dummy 13 socket grammar, §5.19i)
  // Structure (all numbers probed, none guessed):
  //  - socket body: OUTER SPHERE r=4.5 @ origin (rays r=4.4998), clipped z∈[-2.5,2.5]
  //  - ball r=3.000 exact @ (0,7,0) (fit rms 0), plate-clipped z>=-2.5
  //  - neck strut: cylinder r=1.5 along Y (top/side rays both 1.5000 at y=4.4)
  //  - cavity: sphere r=2.900 @ origin (fit rms 0, inliers 1.0) + kit lead-in
  //    cones both faces: r(z) = 2.4689 - 0.3678*(2.5-|z|) (ray-cast r(z) profile)
  //  - mouth wedge: vertical planes y = ±0.6682x through the socket center (§5.12)
  //  - mouth planes carry 45° leg-0.5 face chamfers starting |z|=2.0 (verified
  //    (y-0.6682x)/1.2028 == |z|-2.0 at z=2.4)
  //  - corner cut: kit corner-chamfer line y=±(0.2168x-2.935) at z=0, modulated
  //    in z as a conoid: y < CC - s(z)*(CA - CB*|x|), s=sqrt(1-(z/CZ)^2)
  //    (554-pt ray sample fit rms 0.0042, max 0.014) — built as hulled z-bands

  const outerR = 4.5;
  const sockR = 2.900;
  const ballR = 3.000;
  const strutR = 1.5;
  const mouthS = 0.6682; // |slope| of mouth wedge walls
  const coneRf = 2.4689; // lead-in cone radius at face plane
  const coneM = 0.3678;  // lead-in cone slope (dr/dz)
  const chamZ0 = 2.0;    // mouth face chamfer start |z| (45°, leg 0.5)
  // conoid corner cut params
  const CC = -0.3215, CA = 2.6138, CB = 0.2168, CZ = 3.3882;

  // ---- body ----
  const sockBody = Manifold.sphere(outerR, 128).intersect(Manifold.cube([11, 11, 5], true));
  const ball = Manifold.sphere(ballR, 128).translate([0, 7, 0]);
  const strut = Manifold.cylinder(7, strutR, strutR, 96).rotate([-90, 0, 0]); // along +Y, y∈[0,7]
  let body = sockBody.add(ball).add(strut);

  // plate clip z >= -2.5 (only the ball extends below)
  body = body.intersect(Manifold.cube([11, 15, 5.7], true).translate([0, 3.9, 0.35]));

  // ---- mouth wedge (vertical prism through the socket center) ----
  const yw = 6 * mouthS;
  const wedge2d = geom.fromPoints([[0, 0], [-6, -yw], [-6, -12], [6, -12], [6, -yw]]);
  const wedge = wedge2d.extrude(6.5, 0, 0, [1, 1]).translate([0, 0, -3]);
  body = body.subtract(wedge);

  // ---- mouth-plane 45° leg-0.5 face chamfers (§5.11 wedge prisms) ----
  // profile in (s,z): s = distance along into-material normal from the mouth plane
  const chamProf = geom.fromPoints([[-0.4, chamZ0 - 0.4], [0.8, chamZ0 + 0.8], [0.8, 3.4], [-0.4, 3.4]]);
  // left mouth line: n̂=(-0.5556,0.8314,0), û=(-0.8321,-0.5547,0)=ẑ×n̂
  const thetaL = Math.atan2(0.8314, -0.5556) * 180 / Math.PI;
  const E1 = [5.2 * -0.8321, 5.2 * -0.5547, 0];
  const chamTopLeft = chamProf
    .extrude(5.8, 0, 0, [1, 1])
    .rotate([90, 0, 0])
    .rotate([0, 0, thetaL])
    .translate(E1);
  const chamTopRight = chamTopLeft.mirror([1, 0, 0]);
  const chamTop = chamTopLeft.add(chamTopRight);
  const chamAll = chamTop.add(chamTop.mirror([0, 0, 1]));
  body = body.subtract(chamAll);

  // ---- conoid corner cut (hulled z-bands; hull convexifies, so per side) ----
  function conoidHalfSlab(z, side) {
    // side=-1: left (x<0); returns thin slab whose polygon is the cut region
    const s = Math.sqrt(Math.max(1 - (z / CZ) * (z / CZ), 0));
    const yc = CC - s * CA;            // bound at x=0
    const yo = CC - s * (CA - CB * 4.9); // bound at |x|=4.9
    const pts = side < 0
      ? [[-4.9, -4.5], [0, -4.5], [0, yc], [-4.9, yo]]
      : [[0, -4.5], [4.9, -4.5], [4.9, yo], [0, yc]];
    return geom.fromPoints(pts);
  }
  const bandEdges = [];
  for (let z = -2.5; z <= 2.501; z += 0.25) bandEdges.push(+z.toFixed(4));
  let conoidCut = null;
  for (let i = 0; i + 1 < bandEdges.length; i++) {
    const z1 = bandEdges[i], z2 = bandEdges[i + 1];
    for (const side of [-1, 1]) {
      const a = conoidHalfSlab(z1, side).extrude(0.012, 0, 0, [1, 1]).translate([0, 0, z1]);
      const b = conoidHalfSlab(z2, side).extrude(0.012, 0, 0, [1, 1]).translate([0, 0, z2 - 0.012]);
      const h = a.add(b).hull();
      conoidCut = conoidCut ? conoidCut.add(h) : h;
    }
  }
  body = body.subtract(conoidCut);

  // ---- socket cavity: sphere + two lead-in cone frustums (overshoot faces) ----
  const coneTop = Manifold.cylinder(1.0, coneRf - coneM * 0.8, coneRf + coneM * 0.2, 96).translate([0, 0, 1.7]);
  const coneBot = coneTop.mirror([0, 0, 1]);
  const cavity = Manifold.sphere(sockR, 128).add(coneTop).add(coneBot);
  body = body.subtract(cavity);

  return body;
}

function make_frame_forearm_2x() {
  // frame_forearm_2x — measured reconstruction (sibling of frame_shin_2x, §5.18 transfer)
  // Architecture (every number verified against THIS target's probes/chord math):
  //  - elbow ball: sphere r3.0 c(0,-15,2.5), clipped flat at z=0 (probe fit: rms 0, inliers 1.0)
  //  - neck: Y-prism y -13..-11 of D-profile [circle r1.5 c(0,2.5) cut z>=1.2]
  //    (band area 6.8605 vs analytic D-segment 6.8664; ball overtakes neck at y<=-12.4)
  //  - shaft: chamfered-octagon 5x5 (0.5 x 45deg long-edge chamfers) y -10.5..0,
  //    with a 0.5 x 45deg perimeter chamfer on the -Y end face at y=-11 (hull, faces pinned)
  //  - window slab void z 1.0..4.1 from shaft face y=-5.0 past the spool
  //    (bridge-pair band area 9.00 == analytic exact) — genus handle 1
  //  - wrist spool at (0,0): revolve r2.5, 45deg V-groove to r1.5 @z2.5 (z 1.5..3.5),
  //    0.5 chamfers at z0/z5 faces (r2.0), truncated-cone dimples r1.0->r0.5
  //    depth 0.5 on both faces (z=0.25 hole = circle r0.75 exact) — subtracted LAST

  const SEG = 96;

  // chamfered octagon profile (x,z), half-width hw, z 0..5, 0.5 chamfers
  function oct(hw) {
    return geom.fromPoints([
      [-(hw - 0.5), 0], [hw - 0.5, 0], [hw, 0.5], [hw, 4.5],
      [hw - 0.5, 5], [-(hw - 0.5), 5], [-hw, 4.5], [-hw, 0.5],
    ]);
  }
  // oct(2.5) offset inward by 0.5 (perpendicular, miter) — for the end-face chamfer
  const octSmall = geom.fromPoints([
    [-1.7929, 0.5], [1.7929, 0.5], [2.0, 0.7071], [2.0, 4.2929],
    [1.7929, 4.5], [-1.7929, 4.5], [-2.0, 4.2929], [-2.0, 0.7071],
  ]);
  // extrude an (x,z) CrossSection along +Y from y0 to y1
  function yPrism(cs, y0, y1) {
    return cs.extrude(y1 - y0, 0, 0, [1, 1]).rotate([90, 0, 0]).translate([0, y1, 0]);
  }

  // ---- elbow ball (clipped at z=0) ----
  const ball = Manifold.sphere(3, SEG).translate([0, -15, 2.5])
    .intersect(Manifold.cube([8, 8, 6], false).translate([-4, -19, 0]));

  // ---- neck: D-profile (circle r1.5 c(0,2.5), flat bottom z=1.2) ----
  const neckCS = CrossSection.circle(1.5, SEG).translate([0, 2.5])
    .intersect(CrossSection.square([4, 4], false).translate([-2, 1.2]));
  const neck = yPrism(neckCS, -13, -11.0);

  // ---- shaft end-face chamfer: hull, outer faces pinned on y=-11 and y=-10.5 ----
  const endCh = yPrism(octSmall, -11.0, -10.99)
    .add(yPrism(oct(2.5), -10.5, -10.49)).hull();

  // ---- shaft (runs to spool center; window carves the bridges) ----
  const shaft = yPrism(oct(2.5), -10.5, 0);

  let body = ball.add(neck).add(endCh).add(shaft);

  // ---- window slab void: z 1.0..4.1 from shaft face y=-5.0 (genus handle 1) ----
  const slab = Manifold.cube([7, 8.5, 3.1], false).translate([-3.5, -5.0, 1.0]);
  body = body.subtract(slab);

  // ---- wrist spool at (0,0): revolve profile (r,z) about Z ----
  const spoolProfile = geom.fromPoints([
    [0, 0], [2.0, 0], [2.5, 0.5], [2.5, 1.5], [1.5, 2.5],
    [2.5, 3.5], [2.5, 4.5], [2.0, 5], [0, 5],
  ]);
  const spool = spoolProfile.revolve(SEG);
  body = body.add(spool);

  // ---- dimples: subtract LAST ----
  const dimpleBot = Manifold.cylinder(0.5, 1.0, 0.5, 48, false);
  const dimpleTop = Manifold.cylinder(0.5, 0.5, 1.0, 48, false).translate([0, 0, 4.5]);
  body = body.subtract(dimpleBot).subtract(dimpleTop);

  return body;
}

function make_frame_head() {
  // frame_head — structured rebuild from probe measurements (sibling of
  // frame_hip_and_shoulder: same joint spec, mirrored mouth, keyhole stem).
  // Structure:
  //  - ring disc r=4.5 about socket center (0,0), z 0..5
  //  - front corner-cut flats: line offset 2.9062 along n=(±0.2224,-0.9749), NOT chamfered
  //  - mouth wedge: y <= -0.6682|x| (walls through socket center), full depth
  //  - stem plate z 0..3: walls x=±1.2 (y 4.34..6.1) + traced bulb to y≈8.99
  //  - keyhole slot through stem (z 0..3): straight part x ±0.36 from y 4.4856, traced bulb
  //  - cavity: sphere r=2.8979 @ (0,-0.013,2.5) + rim entry cones r(d)=2.469-0.368d both faces
  //  - 45° leg-0.5 chamfers top+bottom on: outer arc (revolve envelope), mouth lines;
  //    slot front edge chamfered at bottom only (measured 4.486->4.034 @z=0.05)

  const p = { socketR: 2.8979, socketY: -0.013, rimR0: 2.469, rimSlope: 0.368, mouthS: 0.6682, outerR: 4.5, flatOff: 2.9062, cham: 0.5 };

  const S = p.mouthS;      // mouth wall slope (walls: y = -S|x|, through socket center)
  const R = p.outerR;
  const CH = p.cham;
  const H = 5.0;

  // ---------- helpers (from frame_hip_and_shoulder) ----------
  // 45° chamfer wedge cutter for a straight bottom edge (z=0): outward normal n (unit).
  function chamferWedge(e1, e2, n, leg) {
    const prof = geom.fromPoints([[-leg, 0], [-leg, -0.4], [0.6, -0.4], [0.6, leg], [0, leg]]);
    const d = [n[1], -n[0]];
    const v = [e2[0] - e1[0], e2[1] - e1[1]];
    const L = Math.hypot(v[0], v[1]);
    const anchor = (v[0] * d[0] + v[1] * d[1] > 0) ? e1 : e2;
    const phi = Math.atan2(n[1], n[0]) * 180 / Math.PI;
    return prof.extrude(L).rotate([90, 0, 0]).rotate([0, 0, phi]).translate([anchor[0], anchor[1], 0]);
  }
  function mirrorZmid(m) { return m.translate([0, 0, -H / 2]).mirror([0, 0, 1]).translate([0, 0, H / 2]); }
  function rect2D(n, s0, s1, t0, t1) { // rectangle in (n, d) frame: s along n, t along d=(n.y,-n.x)
    const d = [n[1], -n[0]];
    const P = (s, t) => [n[0] * s + d[0] * t, n[1] * s + d[1] * t];
    return geom.fromPoints([P(s0, t0), P(s1, t0), P(s1, t1), P(s0, t1)]);
  }

  // ---------- ring disc + corner-cut flats ----------
  const nCirc = 160;
  const circPts = [];
  for (let i = 0; i < nCirc; i++) {
    const t = (2 * Math.PI * i) / nCirc;
    circPts.push([R * Math.cos(t), R * Math.sin(t)]);
  }
  let base2D = geom.fromPoints(circPts);
  const nFlatR = [0.2224, -0.9749];
  const nFlatL = [-0.2224, -0.9749];
  base2D = base2D.subtract(rect2D(nFlatR, p.flatOff, p.flatOff + 3, -4, 4));
  base2D = base2D.subtract(rect2D(nFlatL, p.flatOff, p.flatOff + 3, -4, 4));

  // outer arc 45° chamfer via exact revolve envelope about the socket axis
  const envProf = geom.fromPoints([
    [0.001, -0.01], [R - CH, -0.01], [R + 0.001, CH], [R + 0.001, H - CH], [R - CH, H + 0.01], [0.001, H + 0.01],
  ]);
  const envelope = envProf.revolve(160);
  let body = base2D.extrude(H, 0, 0, [1, 1]).intersect(envelope);

  // ---------- stem plate (z 0..3) with keyhole bulb (traced, symmetrized) ----------
  const stemLeft = [
    [-1.2, 6.1], [-1.3831, 6.4195], [-1.494, 6.8656], [-1.4932, 7.1422], [-1.4136, 7.5017],
    [-1.1953, 7.9063], [-1.1463, 8.1551], [-1.046, 8.388], [-0.8991, 8.5947], [-0.712, 8.7659],
    [-0.4931, 8.894], [-0.1688, 8.9881],
  ];
  // CCW: up the right side (mirror of left, same order), across the top, down the left side
  const stemPts = [[1.2, 3.8]];
  for (const q of stemLeft) stemPts.push([-q[0], q[1]]);
  for (let i = stemLeft.length - 1; i >= 0; i--) stemPts.push(stemLeft[i]);
  stemPts.push([-1.2, 3.8]);
  const stem = geom.fromPoints(stemPts).extrude(3, 0, 0, [1, 1]);
  body = body.add(stem);

  // ---------- mouth wedge (walls through socket center, chamfered at faces) ----------
  const wedge2D = geom.fromPoints([[0, 0], [-9, -9 * S], [-9, -14], [9, -14], [9, -9 * S]]);
  body = body.subtract(wedge2D.extrude(7, 0, 0, [1, 1]).translate([0, 0, -1]));
  // mouth wall chamfer cutters (bottom pair, then z-mirrored)
  const nm = 1 / Math.hypot(S, 1);
  const nMouthR = [S * nm, -1 * nm];   // outward normal of right wall (solid above y=-Sx)... see note
  // wall on +x side: line y = -S x, solid at y > -S x  => outward normal points down-right:
  // n = (-S, -1)/|.| has dot<0 with solid side; outward from solid into void: (S? ) compute:
  // solid side test point (3,0): y + Sx = 2 > 0 -> solid where y + S|x| > 0 near wall.
  // gradient of (y + Sx) is (S,1); void side is negative -> outward normal = -(S,1)/|.|
  const nWR = [-S * nm, -1 * nm];      // outward normal, right wall
  const nWL = [S * nm, -1 * nm];       // outward normal, left wall (y + S*(-x): grad (-S,1))
  const dWR = [nWR[1], -nWR[0]];
  {
    // right wall edge runs along direction dR = (cos(-33.75deg), sin(-33.75deg))
    const dR = [1 / Math.hypot(1, S), -S / Math.hypot(1, S)];
    const e1 = [2.0 * dR[0], 2.0 * dR[1]];
    const e2 = [4.7 * dR[0], 4.7 * dR[1]];
    body = body.subtract(chamferWedge(e1, e2, nWR, CH));
    body = body.subtract(mirrorZmid(chamferWedge(e1, e2, nWR, CH)));
    const e1L = [-e1[0], e1[1]];
    const e2L = [-e2[0], e2[1]];
    body = body.subtract(chamferWedge(e2L, e1L, nWL, CH));
    body = body.subtract(mirrorZmid(chamferWedge(e2L, e1L, nWL, CH)));
  }

  // ---------- keyhole slot (through stem, z 0..3) ----------
  const slotLeft = [
    [-0.1973, 8.1011], [-0.3201, 7.9647], [-0.4003, 7.6351], [-0.5902, 7.2954], [-0.657, 7.0625],
    [-0.6353, 6.8212], [-0.427, 6.4288], [-0.3627, 6.1675], [-0.36, 6.1],
  ];
  // CCW: up the right side (mirror of left, reversed), top point, down the left side
  const slotPts = [[0.36, 4.4856]];
  for (let i = slotLeft.length - 1; i >= 0; i--) slotPts.push([-slotLeft[i][0], slotLeft[i][1]]);
  slotPts.push([0, 8.153]);
  for (const q of slotLeft) slotPts.push(q);
  slotPts.push([-0.36, 4.4856]);
  const slot = geom.fromPoints(slotPts).extrude(3.5, 0, 0, [1, 1]).translate([0, 0, -0.25]);
  // slot extends z -0.25..3.25: above z=3 the stem is gone; the only overshoot risk is the
  // ring-arc sliver at y 4.486..4.5, |x|<0.36, z 3..5 -> must NOT be cut. Clip slot to z<=3.
  const slotClipped = slot.intersect(Manifold.cube([4, 6, 3.5], true).translate([0, 6.3, 1.5]));
  body = body.subtract(slotClipped);
  // slot front edge bottom chamfer (measured: y 4.486 -> 4.034 at z=0.05)
  body = body.subtract(chamferWedge([-0.36, 4.4856], [0.36, 4.4856], [0, 1], CH));

  // ---------- cavity: socket sphere + rim entry cones (subtract LAST) ----------
  const socket = Manifold.sphere(p.socketR, 128).translate([0, p.socketY, 2.5]);
  const coneBot = Manifold.cylinder(1.1, p.rimR0 + 0.1 * p.rimSlope, p.rimR0 - 1.0 * p.rimSlope, 96)
    .translate([0, p.socketY, -0.1]);
  const coneTop = mirrorZmid(coneBot);
  body = body.subtract(socket).subtract(coneBot).subtract(coneTop);

  return body;
}

function make_frame_hip_and_shoulder_4x() {
  // frame_hip_and_shoulder_4x — structured rebuild from probe measurements.
  // Structure: main block (outline = walls x=±4.5 + arc r=4.5 about socket center
  // + straight corner chamfer lines + mouth lines through center), tab with leg-1.0
  // 45° x-edge chamfers, Ø3 rod along Y, rear r=3 cylinder along Y clipped at z=0.
  // Cavity: sphere r=2.9075 @ (0,0,2.5) + 20° rim entry cones at both faces +
  // full-height mouth wedge (y >= 0.6682|x|). Outer 45° leg-0.5 chamfers (top+bottom)
  // on: x walls, r=4.5 arc, mouth lines ONLY (measured: y=-2.8 / corner-cut / y=-4 /
  // tab end / chamfer-line edges are NOT chamfered).

  const p = { socketR: 2.9075, rimR0: 2.4709, rimSlope: 0.3678, mouthS: 0.6682, outerR: 4.5, rearR: 2.9995, cham: 0.5 };

  const S = p.mouthS;              // mouth line slope: y = S*x (through socket center)
  const R = p.outerR;              // big outline arc radius about socket center
  const CH = p.cham;               // outer chamfer leg
  const H = 5.0;                   // main block height (ray-measured top z=5.0)
  // corner chamfer line (probed): y = A*x + B
  const A = -0.2279, B = 2.9803;
  // chamfer-line endpoints: on mouth line and on arc r=R
  const xm = B / (S - A);                                   // mouth end
  const ym = S * xm;
  const xa = (-A * B + Math.sqrt(A * A * B * B - (1 + A * A) * (B * B - R * R))) / (1 + A * A);
  const ya = A * xa + B;

  // ---------- helpers ----------
  function cylY(r, y0, y1, zc, segs) {
    return Manifold.cylinder(y1 - y0, r, r, segs).rotate([-90, 0, 0]).translate([0, y0, zc]);
  }
  // 45° chamfer wedge cutter for a straight bottom edge (z=0): outward normal n (unit).
  function chamferWedge(e1, e2, n, leg) {
    const prof = geom.fromPoints([[-leg, 0], [-leg, -0.4], [0.6, -0.4], [0.6, leg], [0, leg]]);
    const d = [n[1], -n[0]];
    const v = [e2[0] - e1[0], e2[1] - e1[1]];
    const L = Math.hypot(v[0], v[1]);
    const anchor = (v[0] * d[0] + v[1] * d[1] > 0) ? e1 : e2;
    const phi = Math.atan2(n[1], n[0]) * 180 / Math.PI;
    return prof.extrude(L).rotate([90, 0, 0]).rotate([0, 0, phi]).translate([anchor[0], anchor[1], 0]);
  }
  function mirrorZmid(m) { return m.translate([0, 0, -H / 2]).mirror([0, 0, 1]).translate([0, 0, H / 2]); }

  // ---------- main block outline ----------
  const thArcEnd = Math.atan2(ya, xa); // arc runs from angle 0 to thArcEnd
  const pts = [];
  pts.push([-2.5, -4], [2.5, -4], [3.7, -2.8], [4.5, -2.8], [R, 0]);
  const nArc = 14;
  for (let i = 1; i <= nArc; i++) {
    const t = (thArcEnd * i) / nArc;
    pts.push([R * Math.cos(t), R * Math.sin(t)]);
  }
  pts.push([xm, ym], [-xm, ym], [-xa, ya]);
  for (let i = nArc - 1; i >= 1; i--) {
    const t = (thArcEnd * i) / nArc;
    pts.push([-R * Math.cos(t), R * Math.sin(t)]);
  }
  pts.push([-R, 0], [-4.5, -2.8], [-3.7, -2.8]);
  const base = geom.fromPoints(pts).extrude(H, 0, 0, [1, 1]);

  // ---------- tab (y in [-5,-3.7], leg-1.0 45° chamfers on x edges) ----------
  const tabProf = geom.fromPoints([[-1.5, 0], [1.5, 0], [2.5, 1], [2.5, 4], [1.5, 5], [-1.5, 5], [-2.5, 4], [-2.5, 1]]);
  const tab = tabProf.extrude(1.3, 0, 0, [1, 1]).rotate([90, 0, 0]).translate([0, -3.7, 0]);

  // ---------- rod + rear cylinder ----------
  const rod = cylY(1.5, -7.65, -4.5, 2.5, 64);
  const rearClip = Manifold.cube([12, 3.5, 8]).translate([-6, -10.1, 0]);
  const rear = cylY(p.rearR, -9.9, -7.6, 2.5, 128).intersect(rearClip);

  // ---------- cavity ----------
  const socket = Manifold.sphere(p.socketR, 128).translate([0, 0.002, 2.5]);
  const coneBot = Manifold.cylinder(0.78, p.rimR0 + 0.1 * p.rimSlope, p.rimR0 - 0.68 * p.rimSlope, 96).translate([0, 0.002, -0.1]);
  const coneTop = mirrorZmid(coneBot);
  const wedge2D = geom.fromPoints([[0, 0], [8, 8 * S], [8, 12], [-8, 12], [-8, 8 * S]]);
  const mouthWedge = wedge2D.extrude(7, 0, 0, [1, 1]).translate([0, 0, -1]);

  // ---------- outer 45° chamfer cutters (bottom set, then z-mirrored) ----------
  const cutters = [];
  // x walls (extent exactly y in [-2.8, 0.1])
  cutters.push(chamferWedge([4.5, 0.1], [4.5, -2.8], [1, 0], CH));
  cutters.push(chamferWedge([-4.5, 0.1], [-4.5, -2.8], [-1, 0], CH));
  // mouth lines (from inside cavity rim out past the arc)
  const nm = 1 / Math.hypot(S, 1);
  const nMouth = [-S * nm, 1 * nm];
  const dMouth = [nMouth[1], -nMouth[0]];
  cutters.push(chamferWedge([2.1 * dMouth[0], 2.1 * dMouth[1]], [4.6 * dMouth[0], 4.6 * dMouth[1]], nMouth, CH));
  cutters.push(chamferWedge([-2.1 * dMouth[0], 2.1 * dMouth[1]], [-4.6 * dMouth[0], 4.6 * dMouth[1]], [S * nm, 1 * nm], CH));
  // arc annulus cutter: outside 45° cone about origin, limited to arc sectors
  const ring = Manifold.cylinder(0.75, R + 1, R + 1, 64).translate([0, 0, -0.25]);
  const cone45 = Manifold.cylinder(0.75, R - CH - 0.25, R + 0.25, 128).translate([0, 0, -0.25]);
  const annulus = ring.subtract(cone45);
  const secAngles = [-1.5, 6, 13, 20, 27.6].map((a) => (a * Math.PI) / 180);
  const secPts = [[0, 0]].concat(secAngles.map((t) => [6 * Math.cos(t), 6 * Math.sin(t)]));
  const sector = geom.fromPoints(secPts).extrude(1.2, 0, 0, [1, 1]).translate([0, 0, -0.3]);
  const sectors = sector.add(sector.mirror([1, 0, 0]));
  cutters.push(annulus.intersect(sectors));

  let cutBottom = cutters[0];
  for (let i = 1; i < cutters.length; i++) cutBottom = cutBottom.add(cutters[i]);
  const allCut = cutBottom.add(mirrorZmid(cutBottom));

  // ---------- assemble ----------
  return base.add(tab).add(rod).add(rear)
    .subtract(mouthWedge)
    .subtract(socket)
    .subtract(coneBot)
    .subtract(coneTop)
    .subtract(allCut);
}

function make_frame_hips() {
  // Dummy 13 frame_hips — 3 balls on a D-flat strut, bottom-clipped.
  // All numbers probed:
  //   sphere fits: r=3.000 at (-8,0,0),(0,0,0),(8,0,0)  rms 0, inliers 1.0
  //   strut: cylinder r=1.500 axis +X, rms 0; chordal flat at z=-1.3 (D-section)
  //   bottom clip plane z=-2.5 (bbox zmin; z=-2.48 section circles r=1.6867=sqrt(9-2.48^2))

  const ballR = 3.0;
  const ballX = 8.0;
  const strutR = 1.5;
  const flatZ = -1.3;
  const clipZ = -2.5;

  let s = null;
  for (const x of [-ballX, 0, ballX]) {
    const b = Manifold.sphere(ballR, 128).translate([x, 0, 0]);
    s = s ? s.add(b) : b;
  }

  // D-strut: full-length cylinder along X, flat cut at z=flatZ (cut BEFORE union —
  // the balls are not flattened at that plane, only the strut is)
  let strut = Manifold.cylinder(2 * ballX + 0.4, strutR, strutR, 96, true)
    .rotate([0, 90, 0]);
  strut = strut.subtract(
    Manifold.cube([2 * ballX + 2, 2 * strutR + 2, 3], true)
      .translate([0, 0, flatZ - 1.5])
  );
  s = s.add(strut);

  // bottom clip: keep z >= clipZ
  s = s.intersect(
    Manifold.cube([24, 8, 6.5], true).translate([0, 0, clipZ + 3.25])
  );

  return s;
}

function make_frame_knee_and_elbow_4x() {
  // frame_knee_and_elbow_4x — structured rebuild
  // base: traced z=1.4 outline (channels, ears, V-notch), eye lobe as exact
  // circle r=1.5 @ (3,3.6), socket disks refilled (pac-man: disk r=2.4 minus
