// Flow-pack layout: each part type's copies placed adjacently, every piece
// dropped to the print bed (z=0), 6mm gaps so compose (mesh merge) is valid.
// The original kit STLs (and our faithful reconstructions) carry sub-mm
// export-debris specks (8-40 tris, 0.01-0.5mm) alongside some parts. They
// are not printable geometry - drop any component smaller than 1mm.
function dropDebris(m) {
  const pieces = m.decompose();
  const keep = pieces.filter((p) => {
    const bb = p.boundingBox();
    const d = Math.max(bb.max[0] - bb.min[0], bb.max[1] - bb.min[1], bb.max[2] - bb.min[2]);
    return d >= 1;
  });
  if (keep.length === pieces.length) return m;
  return keep.length === 1 ? keep[0] : Manifold.compose(keep);
}

// Decimate each part within tolerance WITHOUT fusing its separate pieces:
// simplify can weld close-clearance components (articulated hands fuse at
// 0.02+), so verify the component count survives and back off if not.
function safeSimplify(m, tol) {
  const before = m.decompose().length;
  for (const t of [tol, 0.01]) {
    const s = m.simplify(t);
    if (s.decompose().length === before) return s;
  }
  return m;
}

const GAP = 6, PLATE_W = 200;
const plate = [];
let cx = 0, cy = 0, rowH = 0;
for (const p of PARTS) {
  const m = safeSimplify(dropDebris(p.make()), 0.03);
  const bb = m.boundingBox();
  const w = bb.max[0] - bb.min[0], d = bb.max[1] - bb.min[1];
  for (let i = 0; i < p.count; i++) {
    if (cx > 0 && cx + w > PLATE_W) { cx = 0; cy += rowH + GAP; rowH = 0; }
    plate.push(m.translate([cx - bb.min[0], cy - bb.min[1], -bb.min[2]]));
    cx += w + GAP;
    if (d > rowH) rowH = d;
  }
}
const composed = Manifold.compose(plate);
const cb = composed.boundingBox();
// center the plate on the origin in xy, keep bed at z=0 (parts already decimated per-part)
return composed.translate([-(cb.min[0] + cb.max[0]) / 2, -(cb.min[1] + cb.max[1]) / 2, 0]);
